const CHAR_IMAGES = {
  "char1": "data:image/png;base64,",
  "char2": "data:image/png;base64,",
  "char3": "data:image/png;base64,",
  "char4": "data:image/png;base64,",
  "char5": "data:image/png;base64,"
};

const CHAR_KEYS = Object.keys(CHAR_IMAGES);
const loadedImgs = {};
CHAR_KEYS.forEach(key => {
  const img = new Image();
  img.src = CHAR_IMAGES[key];
  loadedImgs[key] = img;
});

const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');
let W, H;
function resize(){ W=canvas.width=window.innerWidth; H=canvas.height=window.innerHeight; }
resize();
window.addEventListener('resize',()=>{ resize(); plate.y=H-100; });

// ===== お皿の設定 =====
// 縁（へり）の高さ — キャラがここでせき止められる
const PLATE_W    = 150;
const PLATE_H    = 18;
const RIM_H      = 18;   // 縁の高さ（大きいほど落ちにくい）
const RIM_W      = 14;   // 縁の幅
const CHAR_R     = 26;

const plate = {
  x:0, y:0, w:PLATE_W, h:PLATE_H, vx:0, prevVx:0,
  get left(){ return this.x - this.w/2; },
  get right(){ return this.x + this.w/2; },
  get top(){ return this.y - this.h/2; },
  // 縁の内側（キャラが乗れる範囲）
  get innerLeft(){ return this.left + RIM_W; },
  get innerRight(){ return this.right - RIM_W; },
};

// ===== 物理定数（4歳向け・安定） =====
const GRAVITY      = 0.16;
const BOUNCE       = 0.05;   // ほぼ跳ねない
const FRICTION     = 0.86;
const PLATE_SPEED  = 5.5;
const INERTIA_MULT = 0.18;   // お皿の慣性影響（小さいほど安定）

function getFallSpeed(){
  const p = Math.min(elapsed/(30*60),1);
  return 0.65 + p*0.85*(0.5+Math.random()*0.5);
}
// spawnInterval: クレーンのwaitFramesで管理

let score=0,highScore=0,gameRunning=false,timeLeft=30,elapsed=0;
let fallings=[],stacked=[],particles=[];
let animId,timerInterval;

class Falling {
  constructor(x, imgKey){
    this.x = x;
    this.y = 80;
    this.vx = (Math.random()-0.5)*0.3;
    this.vy = getFallSpeed();
    this.imgKey = imgKey;
    this.angle = (Math.random()-0.5)*0.15;
    this.active = true;
  }
}

// ===== クレーン =====
const CRANE_STATES = {
  TO_BOX:   'to_box',    // おもちゃ箱へ移動
  DESCEND:  'descend',   // アームを下ろす
  GRAB:     'grab',      // キャラを掴む
  ASCEND:   'ascend',    // アームを上げる
  TO_DROP:  'to_drop',   // ドロップ位置へ移動
  OPEN:     'open',      // アームを開いてリリース
  WAIT:     'wait',      // 少し待機
};

// おもちゃ箱の位置（右上・UIの下）
const BOX = { w: 72, h: 60 };
function getBoxX(){ return W - BOX.w/2 - 18; }
function getBoxY(){ return 130; }  // UIバー(約50px) + レール(約50px) + 余白

const crane = {
  x: 0,
  armY: 0,
  armMaxY: 60,
  armOpenAng: 1,   // 1=全開, 0=閉じ
  state: CRANE_STATES.TO_BOX,
  stateTimer: 0,
  heldImgKey: null,
  dropX: 200,
};

function pickNextChar(){
  crane.heldImgKey = CHAR_KEYS[Math.floor(Math.random()*CHAR_KEYS.length)];
}

function updateCrane(){
  crane.stateTimer++;

  switch(crane.state){

    case CRANE_STATES.TO_BOX: {
      // おもちゃ箱の真上へ移動
      const tx = getBoxX();
      const dx = tx - crane.x;
      const spd = Math.min(Math.abs(dx), 5.5);
      crane.x += Math.sign(dx) * spd;
      crane.armOpenAng = Math.min(1, crane.armOpenAng + 0.06); // アーム開きながら移動
      crane.armY = Math.max(0, crane.armY - 3);
      if(Math.abs(dx) < 2){
        crane.x = tx;
        pickNextChar();
        crane.state = CRANE_STATES.DESCEND;
        crane.stateTimer = 0;
      }
      break;
    }

    case CRANE_STATES.DESCEND:
      // アームが箱に向かって下りる
      crane.armY = Math.min(crane.armMaxY, crane.armY + 2.5);
      crane.armOpenAng = Math.max(0.3, crane.armOpenAng - 0.05);
      if(crane.armY >= crane.armMaxY){
        crane.state = CRANE_STATES.GRAB;
        crane.stateTimer = 0;
      }
      break;

    case CRANE_STATES.GRAB:
      // つめを閉じてキャラを掴む
      crane.armOpenAng = Math.max(0, crane.armOpenAng - 0.08);
      if(crane.stateTimer > 22){
        crane.state = CRANE_STATES.ASCEND;
        crane.stateTimer = 0;
      }
      break;

    case CRANE_STATES.ASCEND:
      // アームを上げる
      crane.armY = Math.max(0, crane.armY - 3.2);
      if(crane.armY <= 0){
        // ドロップ先を決める（お皿の上空あたりランダム）
        crane.dropX = 80 + Math.random()*(W-160);
        crane.state = CRANE_STATES.TO_DROP;
        crane.stateTimer = 0;
      }
      break;

    case CRANE_STATES.TO_DROP: {
      // ドロップ位置へ移動
      const dx = crane.dropX - crane.x;
      const spd = Math.min(Math.abs(dx), 5.0);
      crane.x += Math.sign(dx) * spd;
      if(Math.abs(dx) < 2){
        crane.x = crane.dropX;
        crane.state = CRANE_STATES.OPEN;
        crane.stateTimer = 0;
      }
      break;
    }

    case CRANE_STATES.OPEN:
      // つめが開いてキャラをリリース
      crane.armOpenAng = Math.min(1, crane.armOpenAng + 0.07);
      if(crane.armOpenAng >= 0.95){
        fallings.push(new Falling(crane.x, crane.heldImgKey));
        crane.heldImgKey = null;
        crane.state = CRANE_STATES.WAIT;
        crane.stateTimer = 0;
      }
      break;

    case CRANE_STATES.WAIT:
      if(crane.stateTimer > 18){
        crane.state = CRANE_STATES.TO_BOX;
        crane.stateTimer = 0;
      }
      break;
  }
}

function drawToyBox(){
  const bx = getBoxX(), by = getBoxY();
  const bw = BOX.w, bh = BOX.h;

  ctx.save();

  // 箱の影
  ctx.globalAlpha = 0.15;
  ctx.fillStyle = '#804060';
  ctx.beginPath();
  ctx.ellipse(bx, by + bh/2 + 6, bw*0.45, 6, 0, 0, Math.PI*2);
  ctx.fill();
  ctx.globalAlpha = 1;

  // 箱本体
  const boxGrad = ctx.createLinearGradient(bx-bw/2, by-bh/2, bx+bw/2, by+bh/2);
  boxGrad.addColorStop(0, '#ffe4f0');
  boxGrad.addColorStop(0.5, '#ffcce4');
  boxGrad.addColorStop(1, '#f4a7c3');
  ctx.fillStyle = boxGrad;
  ctx.strokeStyle = '#e8527a';
  ctx.lineWidth = 2.5;
  ctx.shadowColor = 'rgba(244,167,195,0.4)';
  ctx.shadowBlur = 10;
  ctx.beginPath();
  ctx.roundRect(bx-bw/2, by-bh/2, bw, bh, 10);
  ctx.fill(); ctx.stroke();
  ctx.shadowBlur = 0;

  // 箱のふた（上部）
  const lidGrad = ctx.createLinearGradient(bx-bw/2, by-bh/2-10, bx+bw/2, by-bh/2+6);
  lidGrad.addColorStop(0, '#fff0f8');
  lidGrad.addColorStop(1, '#f4a7c3');
  ctx.fillStyle = lidGrad;
  ctx.strokeStyle = '#e8527a';
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.roundRect(bx-bw/2-3, by-bh/2-12, bw+6, 16, 5);
  ctx.fill(); ctx.stroke();

  // リボン（縦）
  ctx.fillStyle = '#e8527a';
  ctx.fillRect(bx-4, by-bh/2-12, 8, bh+12);

  // リボン（横）
  ctx.fillRect(bx-bw/2, by-bh/2+8, bw, 6);

  // リボンの結び目
  ctx.fillStyle = '#ff80a8';
  ctx.strokeStyle = '#e8527a';
  ctx.lineWidth = 1.5;
  ctx.beginPath(); ctx.arc(bx, by-bh/2-4, 7, 0, Math.PI*2); ctx.fill(); ctx.stroke();

  // 箱の中のキャラがちらっと見える
  ctx.globalAlpha = 0.6;
  ctx.font = '18px serif';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText('🐾', bx-12, by+8);
  ctx.fillText('✨', bx+10, by-4);
  ctx.globalAlpha = 1;

  ctx.restore();
}

function drawCrane(){
  const cx = crane.x;
  const railY = 62;           // UIバーの下（UIが約50px）
  const armBaseY = railY + 22;
  const armTipY  = armBaseY + crane.armY;

  ctx.save();

  // ===== レール =====
  const railGrad = ctx.createLinearGradient(0, railY-6, 0, railY+6);
  railGrad.addColorStop(0, '#f8d0e8');
  railGrad.addColorStop(0.5, '#ffffff');
  railGrad.addColorStop(1, '#e8a0c0');
  ctx.fillStyle = railGrad;
  ctx.strokeStyle = '#d888b0';
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  ctx.roundRect(20, railY-6, W-40, 12, 6);
  ctx.fill(); ctx.stroke();

  // レールのネジ
  for(let rx=60; rx<W-40; rx+=80){
    ctx.fillStyle = '#f4c0d8';
    ctx.beginPath(); ctx.arc(rx, railY, 4, 0, Math.PI*2); ctx.fill();
    ctx.fillStyle = '#c07090';
    ctx.beginPath(); ctx.arc(rx, railY, 2, 0, Math.PI*2); ctx.fill();
  }

  // ===== クレーン本体 =====
  const bw = 40, bh = 26;
  const bodyGrad = ctx.createLinearGradient(cx-bw/2, armBaseY-bh, cx+bw/2, armBaseY);
  bodyGrad.addColorStop(0, '#fff0f8');
  bodyGrad.addColorStop(1, '#f4a7c3');
  ctx.shadowColor = 'rgba(244,167,195,0.5)';
  ctx.shadowBlur = 8;
  ctx.fillStyle = bodyGrad;
  ctx.strokeStyle = '#e8527a';
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.roundRect(cx-bw/2, armBaseY-bh, bw, bh, 7);
  ctx.fill(); ctx.stroke();
  ctx.shadowBlur = 0;

  // 点滅ライト
  const blinkOn = Math.floor(elapsed/16)%2===0;
  ctx.fillStyle = blinkOn ? '#ff4080' : '#ffb0cc';
  ctx.beginPath(); ctx.arc(cx, armBaseY-bh*0.55, 4.5, 0, Math.PI*2); ctx.fill();

  // ===== ワイヤー =====
  ctx.strokeStyle = '#c080a8';
  ctx.lineWidth = 2;
  ctx.setLineDash([5, 3]);
  ctx.beginPath();
  ctx.moveTo(cx, armBaseY);
  ctx.lineTo(cx, armTipY - 8);
  ctx.stroke();
  ctx.setLineDash([]);

  // ===== つめ =====
  const openAng  = crane.armOpenAng;
  const clawSize = 18;
  const spread   = 12 + openAng * 16;

  [[-1, -1], [1, 1]].forEach(([side, rotDir]) => {
    ctx.save();
    ctx.translate(cx + side * spread * 0.5, armTipY);
    ctx.rotate(rotDir * (0.25 + openAng * 0.45));
    const cg = ctx.createLinearGradient(-3, -clawSize, 3, 0);
    cg.addColorStop(0, '#f4a7c3');
    cg.addColorStop(1, '#e8527a');
    ctx.fillStyle = cg;
    ctx.strokeStyle = '#c04060';
    ctx.lineWidth = 1.8;
    ctx.beginPath();
    ctx.moveTo(0, 0);
    ctx.lineTo(side * -5, -clawSize);
    ctx.lineTo(side * 5, -clawSize * 0.65);
    ctx.lineTo(side * 7, clawSize * 0.28);
    ctx.closePath();
    ctx.fill(); ctx.stroke();
    ctx.restore();
  });

  // ===== 掴んでいるキャラ =====
  const isHolding = crane.heldImgKey &&
    (crane.state === CRANE_STATES.DESCEND ||
     crane.state === CRANE_STATES.GRAB ||
     crane.state === CRANE_STATES.ASCEND ||
     crane.state === CRANE_STATES.TO_DROP);
  if(isHolding){
    const wobble = Math.sin(elapsed * 0.06) * 0.07;
    drawCharImg(cx, armTipY + CHAR_R*0.7, crane.heldImgKey, wobble, 1, 1);
  }

  ctx.restore();
}

class Stacked {
  constructor(x,y,imgKey,vx,vy){
    this.x=x; this.y=y;
    this.vx=vx||0; this.vy=vy||0;
    this.imgKey=imgKey;
    this.angle=(Math.random()-0.5)*0.1;
    this.angVel=0;
    this.fallen=false;
    this.landAnim=1.25;
  }
}

function spawnParticles(x,y,color,n){
  for(let i=0;i<(n||8);i++){
    const a=Math.random()*Math.PI*2,spd=1.5+Math.random()*3;
    particles.push({x,y,vx:Math.cos(a)*spd,vy:Math.sin(a)*spd-1.5,r:4+Math.random()*4,color,life:40,maxLife:40});
  }
}

function showFloat(x,y,text){
  const el=document.createElement('div');
  el.className='float-text'; el.textContent=text;
  el.style.left=(x-16)+'px'; el.style.top=(y-16)+'px';
  document.body.appendChild(el);
  setTimeout(()=>el.remove(),900);
}

let warnTO=null;
function showWarning(){
  const el=document.getElementById('warningMsg');
  el.style.display='block';
  clearTimeout(warnTO);
  warnTO=setTimeout(()=>el.style.display='none',1200);
}

// ===== 背景 =====
function drawBackground(){
  const sky=ctx.createLinearGradient(0,0,0,H);
  sky.addColorStop(0,'#fce4f0'); sky.addColorStop(0.65,'#fdf0f5'); sky.addColorStop(1,'#f0f9f4');
  ctx.fillStyle=sky; ctx.fillRect(0,0,W,H);
  ctx.fillStyle='#f4e8ed'; ctx.fillRect(0,H-36,W,36);
  ctx.fillStyle='#e8d0dc'; ctx.fillRect(0,H-38,W,4);
  drawCloud(W*0.1,H*0.09,52,0.18); drawCloud(W*0.55,H*0.06,68,0.14); drawCloud(W*0.85,H*0.13,44,0.16);
}
function drawCloud(x,y,r,a){
  ctx.save(); ctx.globalAlpha=a; ctx.fillStyle='#fff';
  [[0,0,1],[0.55,0.18,0.78],[-0.5,0.2,0.7],[0.28,-0.15,0.65]].forEach(([dx,dy,s])=>{
    ctx.beginPath(); ctx.arc(x+dx*r,y+dy*r,r*s,0,Math.PI*2); ctx.fill();
  });
  ctx.restore();
}

// ===== お皿（縁つき） =====
function drawPlate(){
  const {x,y,w,h} = plate;

  // 影
  ctx.save(); ctx.globalAlpha=0.12; ctx.fillStyle='#b06080';
  ctx.beginPath(); ctx.ellipse(x,y+h/2+10,w*0.5,6,0,0,Math.PI*2); ctx.fill(); ctx.restore();

  ctx.save();
  ctx.shadowColor='rgba(244,167,195,0.5)'; ctx.shadowBlur=16;

  // お皿の本体（平らな部分）
  const grad=ctx.createLinearGradient(x-w/2,y-4,x+w/2,y+h);
  grad.addColorStop(0,'#fff8fb'); grad.addColorStop(0.5,'#ffffff'); grad.addColorStop(1,'#f4d8e8');
  ctx.fillStyle=grad; ctx.strokeStyle='#e8a0bf'; ctx.lineWidth=2.5;
  ctx.beginPath(); ctx.ellipse(x,y,w/2,h/2,0,0,Math.PI*2); ctx.fill(); ctx.stroke();

  // 左の縁（へり）
  const rimGrad=ctx.createLinearGradient(x-w/2,y-RIM_H,x-w/2+RIM_W,y);
  rimGrad.addColorStop(0,'#f9d0e4'); rimGrad.addColorStop(1,'#ffffff');
  ctx.fillStyle=rimGrad; ctx.strokeStyle='#e8a0bf'; ctx.lineWidth=2;
  ctx.beginPath();
  ctx.moveTo(x-w/2, y+h/2);
  ctx.lineTo(x-w/2, y-RIM_H);
  ctx.quadraticCurveTo(x-w/2+RIM_W*0.5, y-RIM_H-4, x-w/2+RIM_W, y-h/2);
  ctx.lineTo(x-w/2+RIM_W, y+h/2);
  ctx.closePath();
  ctx.fill(); ctx.stroke();

  // 右の縁（へり）
  const rimGrad2=ctx.createLinearGradient(x+w/2,y-RIM_H,x+w/2-RIM_W,y);
  rimGrad2.addColorStop(0,'#f9d0e4'); rimGrad2.addColorStop(1,'#ffffff');
  ctx.fillStyle=rimGrad2;
  ctx.beginPath();
  ctx.moveTo(x+w/2, y+h/2);
  ctx.lineTo(x+w/2, y-RIM_H);
  ctx.quadraticCurveTo(x+w/2-RIM_W*0.5, y-RIM_H-4, x+w/2-RIM_W, y-h/2);
  ctx.lineTo(x+w/2-RIM_W, y+h/2);
  ctx.closePath();
  ctx.fill(); ctx.stroke();

  // ハイライト
  ctx.globalAlpha=0.4; ctx.fillStyle='#fff'; ctx.shadowBlur=0;
  ctx.beginPath(); ctx.ellipse(x-w*0.12,y-h*0.12,w*0.18,h*0.18,-0.4,0,Math.PI*2); ctx.fill();

  ctx.restore();
}

// ===== キャラ描画 =====
function drawCharImg(x,y,imgKey,angle,opacity,scale){
  const img=loadedImgs[imgKey];
  if(!img||!img.complete) return;
  const s=CHAR_R*2.4*(scale||1);
  ctx.save();
  ctx.globalAlpha=opacity;
  ctx.translate(x,y); ctx.rotate(angle);
  ctx.drawImage(img,-s/2,-s/2,s,s);
  ctx.restore();
}

// ===== 物理ステップ =====
function physicsStep(){
  const delta = plate.vx - plate.prevVx;

  for(let i=0;i<stacked.length;i++){
    const s=stacked[i];
    if(s.fallen) continue;
    if(s.landAnim>1) s.landAnim=Math.max(1,s.landAnim-0.035);

    // お皿慣性
    s.vx += delta * INERTIA_MULT;
    s.vy += GRAVITY;
    s.vx *= FRICTION;
    s.angVel += s.vx*0.007;
    s.angVel *= 0.84;
    s.angle += s.angVel;
    s.x += s.vx; s.y += s.vy;

    // ===== お皿の縁による横方向のブロック =====
    // 左縁の内側
    if(s.x - CHAR_R < plate.innerLeft && s.x > plate.left){
      s.x = plate.innerLeft + CHAR_R;
      s.vx = Math.abs(s.vx)*0.2; // 弾き返し（小さく）
    }
    // 右縁の内側
    if(s.x + CHAR_R > plate.innerRight && s.x < plate.right){
      s.x = plate.innerRight - CHAR_R;
      s.vx = -Math.abs(s.vx)*0.2;
    }

    // お皿上面との衝突
    const plateTop=plate.top;
    if(s.vy>=0 && s.y+CHAR_R>plateTop-2 && s.y-CHAR_R<plate.y+PLATE_H/2+4
       && s.x>plate.left-CHAR_R*0.3 && s.x<plate.right+CHAR_R*0.3){
      s.y=plateTop-CHAR_R;
      s.vy*=-BOUNCE; if(Math.abs(s.vy)<0.3) s.vy=0;
      s.vx+=plate.vx*0.03;
    }

    // 他キャラとの衝突（上下の積み重なり＋同じ段の横押し出し）
    for(let j=0;j<i;j++){
      const o=stacked[j]; if(o.fallen) continue;
      const dx=s.x-o.x, dy=s.y-o.y;
      const dist=Math.sqrt(dx*dx+dy*dy);
      const minD=CHAR_R*1.85; // 横方向も確実に離すため少し広め
      if(dist<minD&&dist>0.1){
        const nx=dx/dist, ny=dy/dist;
        const ov=minD-dist;
        if(ny<0){
          // 上から乗っている：縦方向に押し上げ
          s.x+=nx*ov*0.5; s.y+=ny*ov*0.5;
          if(s.vy>0){ s.vy*=-BOUNCE; s.vx+=(Math.random()-0.5)*0.25; }
        } else if(Math.abs(ny)<0.55){
          // ほぼ同じ高さ（同じ段）：横方向に押し出す
          s.x += nx * ov * 0.7;
          s.vx += nx * 0.5;
          // 相手も少し動かして互いに離れる
          o.x -= nx * ov * 0.3;
          o.vx -= nx * 0.25;
        }
      }
    }

    if(s.y>H+80){
      s.fallen=true;
      showWarning();
      spawnParticles(Math.max(20,Math.min(W-20,s.x)),H-20,'#f4a7c3',6);
    }
  }
}

// ===== メインループ =====
function gameLoop(){
  if(!gameRunning) return;
  elapsed++;

  plate.prevVx=plate.vx;
  let dx=0;
  if(keys['ArrowLeft']||keys['a']) dx-=1;
  if(keys['ArrowRight']||keys['d']) dx+=1;
  if(touchActive){
    const diff=touchTargetX-plate.x;
    if(Math.abs(diff)>6) dx=diff>0?Math.min(1,diff/50):Math.max(-1,diff/50);
  }
  plate.vx=dx*PLATE_SPEED;
  if(!dx&&!touchActive) plate.vx*=0.6;
  plate.x+=plate.vx;
  plate.x=Math.max(plate.w/2+8,Math.min(W-plate.w/2-8,plate.x));

  // クレーン更新
  updateCrane();

  fallings=fallings.filter(f=>{
    if(!f.active) return false;
    f.vy+=0.055; f.x+=f.vx; f.y+=f.vy;

    const plateTop=plate.top;
    // お皿に着地
    if(f.vy>0 && f.y+CHAR_R>plateTop-2 && f.y<plate.y+PLATE_H/2+4
       && f.x>plate.left-CHAR_R*0.4 && f.x<plate.right+CHAR_R*0.4){
      // 縁の外に落ちそうなら内側に補正
      let lx=f.x;
      lx=Math.max(plate.innerLeft+CHAR_R, Math.min(plate.innerRight-CHAR_R, lx));
      // 同じ段（1段目）のキャラと被らないよう補正
      for(const other of stacked){
        if(other.fallen) continue;
        const odx=lx-other.x, ody=(plateTop-CHAR_R)-other.y;
        const od=Math.sqrt(odx*odx+ody*ody);
        if(od<CHAR_R*1.85 && od>0.1){
          lx += (odx/od)*(CHAR_R*1.85-od);
          lx=Math.max(plate.innerLeft+CHAR_R, Math.min(plate.innerRight-CHAR_R, lx));
        }
      }
      const ns=new Stacked(lx,plateTop-CHAR_R,f.imgKey,plate.vx*0.04,f.vy*-BOUNCE);
      stacked.push(ns);
      score++; document.getElementById('scoreDisplay').textContent=score;
      spawnParticles(f.x,plateTop,'#f4a7c3',8);
      showFloat(f.x,plateTop-30,'+1 🐾');
      f.active=false; return false;
    }

    // 積みキャラに着地
    for(const s of stacked){
      if(s.fallen) continue;
      const dx=f.x-s.x, dy=f.y-s.y;
      const dist=Math.sqrt(dx*dx+dy*dy);
      if(dist<CHAR_R*1.65&&f.vy>0&&dy<0){
        // 着地X位置：同じ高さのキャラと被らないよう補正
        let lx=f.x;
        const landY=s.y-CHAR_R*1.7;
        for(const other of stacked){
          if(other.fallen||other===s) continue;
          const odx=lx-other.x, ody=landY-other.y;
          const od=Math.sqrt(odx*odx+ody*ody);
          if(od<CHAR_R*1.85 && od>0.1){
            lx += (odx/od)*(CHAR_R*1.85-od);
          }
        }
        const ns=new Stacked(lx,landY,f.imgKey,plate.vx*0.03+(Math.random()-0.5)*0.15,f.vy*-BOUNCE);
        stacked.push(ns);
        score++; document.getElementById('scoreDisplay').textContent=score;
        spawnParticles(f.x,s.y-CHAR_R,'#f7c87e',8);
        showFloat(f.x,s.y-CHAR_R-30,'+1 🐾');
        f.active=false; return false;
      }
    }

    if(f.y>H+60){ f.active=false; return false; }
    return true;
  });

  physicsStep();

  particles=particles.filter(p=>{
    p.x+=p.vx; p.y+=p.vy; p.vy+=0.18; p.vx*=0.93; p.life--;
    return p.life>0;
  });

  ctx.clearRect(0,0,W,H);
  drawBackground();
  drawToyBox();
  drawCrane();

  for(const p of particles){
    ctx.save(); ctx.globalAlpha=p.life/p.maxLife;
    ctx.fillStyle=p.color; ctx.shadowColor=p.color; ctx.shadowBlur=6;
    ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2); ctx.fill(); ctx.restore();
  }

  // 落下キャラ（着地予測の薄い影）
  for(const f of fallings){
    if(!f.active) continue;
    const shadowY=Math.min(plate.top-4,H-20);
    const dist=shadowY-f.y;
    ctx.save(); ctx.globalAlpha=0.07*Math.max(0,1-dist/(H*0.8));
    ctx.fillStyle='#b06080';
    ctx.beginPath(); ctx.ellipse(f.x,shadowY,CHAR_R*0.6,4,0,0,Math.PI*2); ctx.fill(); ctx.restore();
    drawCharImg(f.x,f.y,f.imgKey,f.angle,1,1);
  }

  drawPlate();

  for(const s of stacked){
    if(s.fallen) continue;
    drawCharImg(s.x,s.y,s.imgKey,s.angle,1,s.landAnim);
  }

  // タイマーバー
  const barW=(timeLeft/30)*W;
  ctx.fillStyle=timeLeft<=5?'rgba(231,76,60,0.2)':'rgba(244,167,195,0.2)';
  ctx.fillRect(0,H-8,barW,8);
  ctx.fillStyle=timeLeft<=5?'#e74c3c':'#f4a7c3';
  ctx.fillRect(0,H-8,barW,4);

  animId=requestAnimationFrame(gameLoop);
}

function startTimer(){
  timeLeft=30;
  document.getElementById('timerVal').textContent=30;
  document.getElementById('timerDisplay').classList.remove('urgent');
  timerInterval=setInterval(()=>{
    timeLeft--;
    document.getElementById('timerVal').textContent=timeLeft;
    if(timeLeft<=5) document.getElementById('timerDisplay').classList.add('urgent');
    if(timeLeft<=0) endGame();
  },1000);
}

function startGame(){
  score=0; elapsed=0; spawnTimer=0;
  plate.x=W/2; plate.y=H-100; plate.vx=0; plate.prevVx=0;
  fallings=[]; stacked=[]; particles=[];
  crane.x=getBoxX(); crane.armY=0; crane.armOpenAng=1;
  crane.state=CRANE_STATES.TO_BOX; crane.stateTimer=0; crane.heldImgKey=null;
  document.getElementById('scoreDisplay').textContent='0';
  document.getElementById('overlay').style.display='none';
  document.getElementById('warningMsg').style.display='none';
  gameRunning=true;
  startTimer(); gameLoop();
}

function endGame(){
  gameRunning=false; cancelAnimationFrame(animId); clearInterval(timerInterval);
  if(score>highScore) highScore=score;
  document.getElementById('highScoreDisplay').textContent=highScore;
  document.getElementById('finalScore').textContent=score;
  document.getElementById('highScoreResult').textContent=`ベスト: ${highScore}匹`;
  const emoji=score>=12?'🎊':score>=6?'🌸':score>=3?'🐾':'😴';
  document.getElementById('resultChar').textContent=emoji;
  document.getElementById('startPanel').style.display='none';
  document.getElementById('resultPanel').style.display='';
  document.getElementById('overlay').style.display='flex';
}

let keys={},touchActive=false,touchTargetX=0;
const isMobile=/Mobi|Android|iPhone|iPad/i.test(navigator.userAgent);
if(isMobile) document.getElementById('mobileControls').style.display='flex';

document.addEventListener('keydown',e=>{keys[e.key]=true;});
document.addEventListener('keyup',e=>{keys[e.key]=false;});
canvas.addEventListener('mousemove',e=>{if(gameRunning){touchActive=true;touchTargetX=e.clientX;}});
canvas.addEventListener('mouseleave',()=>{touchActive=false;});
canvas.addEventListener('touchmove',e=>{e.preventDefault();if(gameRunning){touchActive=true;touchTargetX=e.touches[0].clientX;}},{passive:false});
canvas.addEventListener('touchend',()=>{touchActive=false;});

const btnL=document.getElementById('btn-left'),btnR=document.getElementById('btn-right');
btnL.addEventListener('touchstart',e=>{e.preventDefault();keys['ArrowLeft']=true;},{passive:false});
btnL.addEventListener('touchend',()=>keys['ArrowLeft']=false);
btnR.addEventListener('touchstart',e=>{e.preventDefault();keys['ArrowRight']=true;},{passive:false});
btnR.addEventListener('touchend',()=>keys['ArrowRight']=false);
btnL.addEventListener('mousedown',()=>keys['ArrowLeft']=true); btnL.addEventListener('mouseup',()=>keys['ArrowLeft']=false);
btnR.addEventListener('mousedown',()=>keys['ArrowRight']=true); btnR.addEventListener('mouseup',()=>keys['ArrowRight']=false);

document.getElementById('startBtn').addEventListener('click',startGame);
document.getElementById('retryBtn').addEventListener('click',()=>{document.getElementById('resultPanel').style.display='none';startGame();});

resize(); plate.y=H-100;
crane.x = typeof getBoxX === 'function' ? getBoxX() : W-54;
drawBackground(); drawToyBox(); drawCrane(); drawPlate();